import{_ as e,o as a,c as t,j as r,a as p,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"八门遁甲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/能量类/八门遁甲.md","filePath":"4.资源分区/6.技艺及称号/能量类/八门遁甲.md"}'),n={name:"4.资源分区/6.技艺及称号/能量类/八门遁甲.md"};function s(o,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"八门遁甲",tabindex:"-1"},[p("八门遁甲 "),r("a",{class:"header-anchor",href:"#八门遁甲","aria-label":'Permalink to "八门遁甲"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"新世短歌038")])])],-1),d('<h1 id="八门遁甲-1" tabindex="-1">八门遁甲 <a class="header-anchor" href="#八门遁甲-1" aria-label="Permalink to &quot;八门遁甲&quot;">​</a></h1><p>八门遁甲</p><p>介绍：来自《火影忍者》世界当中的禁术，其核心原理在于在人体内，存在着限制查克拉流量的‘门’。它们是保护器，也是枷锁。将这八道生死之门强行冲破，八门遁甲的使用者就能够在短时间内获得超越影级数十倍力量。</p><p>开门<br> 价格：D+500<br> 前提：拥有查克拉能量池，拥有“木叶忍者”称号下的技艺“体术忍者”<br> 描述：八门遁甲的第一门，通过解除脑部的限制，将施术者肉身所潜藏的力量进行百分之百的发挥。<br> 你可以消耗2点查克拉，以一个花招动作开启“开门”，持续一个场景。在开启“开门”之后，你的移动速度提升10米，生理属性检定获得3dp修行加值。</p><p>休门<br> 价格：D+500<br> 前提：兑换“开门”，具有起码1点传奇耐力。<br> 描述：八门遁甲的第二门，在解除这一限制后，你能够从自己的身体当中源源不断地压榨体力，无视疲劳地进行战斗。它仿佛在身体深处打开了一个永不枯竭的体力泉眼，澎湃的力量源源不断地涌出，将所有疲惫感一扫而空。<br> 在开启“开门”的前提下，你可以消耗2点查克拉，以一个花招动作开启“休门”，持续一个场景。在开启“休门”之后，你免疫疲乏点数对你造成的减值以及其严重状态。<br> 即使全力做出攻击，你现在也不会因为肉体的疲劳而露出任何的破绽。在开启“休门”之后，你以生理属性进行的进行的近战攻击视为全力攻击，你全力攻击受到基础防御上的减值减少2点；你现在可以不知疲倦地快速做出连续的攻击，你的近战攻击具有【连射】。</p><p>生门<br> 价格：C+1000<br> 前提：兑换“休门”<br> 描述：八门遁甲的第三门，是八门遁甲最后的安全区，在施展这一门之后，施术者浑身的血液在高压下急速奔流，使得你的皮肤呈现出不自然的赤红色，体表开始散发出微弱的热气，那胀痛与灼热感，预示着前方已是危险的领域。<br> 在开启“休门”的前提下，你可以消耗6点查克拉，以一个迅捷动作开启“生门”，持续一个场景。在开启“生门”之后，在先前的基础上，你的生理属性检定再获得传奇耐力点dp上的修行加值，移动速度提升10米。<br> 由于你的肉身力量得到“生门”开启后的强化。在开启“生门”之后，现在只要你的查克拉能量池不为空，一轮一次，你可以用自由动作将一次冲撞结合在你的一次以生理属性为关键属性的近战攻击中。同时你在“生门”开启期间，由于反应速度得到极大的提升，在反射豁免上具有【8加骰】。</p><p>伤门<br> 价格：C+1000<br> 前提：兑换“生门”<br> 描述：八门遁甲的第四门，是真正踏入危险区域的开始。开启此门后，更庞大的查克拉在体内暴走，疼痛如影随形，但克服这苦痛，你便可以发挥出远超平时的力量与速度。<br> 在开启“生门”的前提下，你可以消耗6点查克拉，以一个移动动作开启“伤门”，持续一个场景。在开启“伤门”之后，在先前的基础上，你的生理属性检定再获得传奇耐力点dp上的修行加值，移动速度再提升10米。<br> 从伤门开始，你在开启八门遁甲期间具有【八门爆发】特性。<br> 【八门爆发】：通过爆发超过身体承受限度的查克拉来施展体术。在开启八门遁甲的当轮以及后续每一轮开始时，你从以下效果中选择一项生效，这会替换原先选择的效果，每次发动八门爆发，都会对你造成4L的不可豁免的严重伤害（注意，这部分伤害是使用时承受，若多次使用需要分别承受）。<br> 八门爆发·速：你在这一轮内，你进行的移动视为C级别的来源的传送移动，这在画风上表现为你进行了一次难以目视的迅速移动，从敌人的眼前消失，然后瞬间来到另一地点，接着移动后的下一次近战攻击附带有B级别的【先制】效果。<br> 八门爆发·力：你在这一轮内，进行的肉搏攻击额外具有【破甲15】。</p><p>杜门<br> 价格：B+2000<br> 前提：兑换“伤门”<br> 描述：八门遁甲的第五门，速度提升到能够通过高速移动摩擦空气产生残影，力量也产生了质的飞跃,但作为代价，对身体的负荷也会急剧增加。<br> 在开启“伤门”的前提下，你可以消耗10点查克拉，以一个移动动作开启“杜门”，持续一个场景。在开启“伤门”之后，在先前的基础上，你的生理属性检定再获得传奇耐力点dp上的修行加值，移动速度再提升60米。在开启杜门的情况下，你的【八门爆发】的效果发生如下变更，这将取代伤门为你带来的【八门爆发】效果：<br> 【八门爆发·杜】：通过爆发超过身体承受限度的查克拉来施展体术。在开启八门遁甲的当轮以及后续每一轮开始时，你从以下效果中选择一项生效，这会替换原先选择的效果，每次发动八门爆发，都会对你造成6L的不可豁免的严重伤害。<br> 八门爆发·速：你在这一轮内，进行的移动视为B级别的时空来源的传送移动，这在画风上表现为你进行了一次难以目视的迅速移动，从敌人的眼前消失，然后瞬间来到另一地点，接着移动后的下一次近战攻击附带有A级别的【先制】效果。<br> 八门爆发·力：你在这一轮内，进行的肉搏攻击额外具有【破甲30】和【幻灭】。</p><p>——暂不开放——<br> 景门<br> 前提：兑换“杜门”<br> 描述：八门遁甲的第六门，开启后从身体中溢出的查克拉会变为萦绕在你身体周围的青绿色蒸汽，这是查克拉燃烧到极致的表现。<br> 惊门<br> 前提：兑换“景门”<br> 描述：八门遁甲的第七门，解除脑部和身体最后的限制器。开启后身体会散发出蓝色的蒸汽，这是查克拉剧烈燃烧蒸发汗液所产生的景象，使用者的力量、速度都将达到一个匪夷所思的境界。<br> 死门<br> 价格：S+8000<br> 前提：兑换“惊门”<br> 描述：八门遁甲所要解除的最终限制，位于心脏。至此，八门遁甲全部开启，这一状态也被称为“八门遁甲之阵”，足以让施展这一术的使用者发挥出数十倍于五影的恐怖实力。渗出的血液化作血红的蒸汽——你的生命也将如同那鲜红的颜色一般，化作落下的秋叶，化为尘土，消散殆尽。</p><p>下属技艺：<br> 特殊的，当你购买影舞叶后，你在进行购买表莲华/里莲华的同时，会同时习得另一个未购买的招式，因此获得的招式无法满足资源购买条件或是要求。</p><p>影舞叶<br> 价格：C+1000<br> 描述：一种速度极快的体术，高速移动到敌人的近前，并以连续的踢击将对手送上半空，是表里莲华的起手式。<br> 以一个标准动作和6点查克拉，你可以选择立刻移动10米距离，之后你进行一次肉搏攻击，这次肉搏攻击具有【高速10】。当你这次攻击命中之后，对方必须以自己的反射豁免对抗你的攻击检定出目，如果对方失败，对方将被向上击飞失败数+30米，并陷入C级别、创伤来源的击飞状态一轮。</p><p>表莲华<br> 价格：C+1000<br> 描述：快速向上跃起，随后将对手束缚，强迫对手落下来承受坠落所造成的冲击。<br> 需求：目标处于空中<br> 你可以消耗一个标准动作和6点查克拉，对处于空中的单位施展表莲华。你对触及范围内的目标进行一次肉搏擒抱，当你赢得了擒抱对抗后，目标会因被你擒抱而与你一同从空中立即向地面开始坠落，当接触地面后，你立即解除与对方的擒抱状态并进行一次肉搏攻击，目标以反射豁免，失败则受到差额的钝击伤害。与被你擒抱的单位不同，你无需承受因坠落而受到的坠落伤害。在计算因此招式造成的坠落伤害时，以60米进行计算。</p><p>里莲华<br> 价格：C+1000<br> 描述：在开启八门遁甲之后才能够施展的体术，快速向上跃起，随后将对手束缚，强迫对手落下来承受坠落所造成的冲击。<br> 以一个标准动作和6点查克拉，你可以施展里莲华。里莲华的施展的要求是在这一回合内必须已经施展过影叶舞，并且必须对因影叶舞效果而浮空的敌人施展。<br> 里莲华是一次可以结合在一次移动当中的攻击，并且额外具有2点技艺加值和3点附加成功。在施展里莲华的这一回合中，你视为具有机动性为普通的飞行能力。<br> 由于向上击飞和向下坠落之间两道不同方向的劲力对敌人躯体造成的压力，这次攻击将具有【碾压】特性。</p><p>朝孔雀<br> 价格：B+2000<br> 描述：通过超高速挥拳与空气摩擦产生火焰，形成覆盖战场的火焰攻击。招式名称源自攻击时火焰如孔雀开屏般展开的姿态。<br> 以一个整轮动作和10点查克拉，你可以施展朝孔雀。你以超高速的正拳击打空气，摩擦产生大量的火焰冲击波，如同孔雀开屏般绚烂，覆盖前方半径120米范围内的锥形区域。<br> 朝孔雀是一次肉搏攻击，这次攻击改为造成火焰伤害，并且由于你以连续的超高速攻击提升攻击的威力，这次攻击的检定出目变为1.5倍。朝孔雀的攻击如同火雨投射，令敌人难以闪避，这次攻击还将具有忽略敌人一半闪避防御的效果，这是一个B级别的时空来源的效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const m=e(n,[["render",s]]);export{f as __pageData,m as default};
